#define HEADER_SIZE 10

typedef struct {
    char key[50];
    char value[100];
} HeaderEntry;

typedef struct {
    HeaderEntry entries[HEADER_SIZE];
    int count;
} HeaderDict;
// हेडर शब्दकोशस्य कुञ्जस्य सूचकांकस्य शोधनस्य कार्यम्, यदि न प्राप्नोति तर्हि -1 प्रतिफलं ददातिint find_header_index(const HeaderDict *header, const char *key) {
    for (int i = 0; i < header->count; i++) {
        if (strcmp(header->entries[i].key, key) == 0) {
            return i;
        }
    }
